import React, { useState, useEffect, useCallback } from "react";
import { useParams, useNavigate } from "react-router-dom";
import api from "../../services/api";

// ── helpers ────────────────────────────────────────────────────────────────────
const PAGE_SIZE = 10;

const GOLD_BORDER =
  "border-2 border-yellow-400 shadow-[0_0_12px_2px_rgba(234,179,8,0.35)]";
const GOLD_BADGE =
  "inline-flex items-center gap-1 bg-yellow-400 text-yellow-900 text-[10px] font-bold px-2 py-0.5 rounded-full uppercase tracking-wider";

// ── sub-components ─────────────────────────────────────────────────────────────

/** Confirmation modal générique */
function ConfirmModal({ open, title, message, onConfirm, onCancel, danger }) {
  if (!open) return null;
  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm">
      <div className="bg-white rounded-2xl shadow-2xl p-8 w-full max-w-md mx-4 animate-fade-in">
        <h3 className={`text-xl font-bold mb-2 ${danger ? "text-red-600" : "text-green-700"}`}>
          {title}
        </h3>
        <p className="text-gray-600 mb-6 text-sm">{message}</p>
        <div className="flex justify-end gap-3">
          <button
            onClick={onCancel}
            className="px-4 py-2 rounded-xl border border-gray-200 text-gray-600 hover:bg-gray-50 text-sm font-medium transition"
          >
            Annuler
          </button>
          <button
            onClick={onConfirm}
            className={`px-5 py-2 rounded-xl text-white text-sm font-semibold transition shadow ${
              danger
                ? "bg-red-600 hover:bg-red-700"
                : "bg-green-600 hover:bg-green-700"
            }`}
          >
            Confirmer
          </button>
        </div>
      </div>
    </div>
  );
}

/** Ligne du tableau pour un candidat */
function CandidateRow({ candidate, rank, isGold, onDelete, onApprove }) {
  const [deleteOpen, setDeleteOpen] = useState(false);
  const [approveOpen, setApproveOpen] = useState(false);

  const statusColors = {
    EN_ATTENTE: "bg-yellow-100 text-yellow-800",
    APPROUVE: "bg-green-100 text-green-800",
    REJETE: "bg-red-100 text-red-800",
  };

  return (
    <>
      {/* Delete modal */}
      <ConfirmModal
        open={deleteOpen}
        title="Supprimer ce candidat ?"
        message={`Voulez-vous vraiment supprimer ${candidate.nomPrenom || candidate.name || "ce candidat"} ? Cette action est irréversible.`}
        danger
        onConfirm={() => { setDeleteOpen(false); onDelete(candidate.id); }}
        onCancel={() => setDeleteOpen(false)}
      />

      {/* Approve modal */}
      <ConfirmModal
        open={approveOpen}
        title="Approuver ce candidat ?"
        message={`Un email personnalisé sera envoyé à ${candidate.email || "ce candidat"} via le workflow n8n.`}
        danger={false}
        onConfirm={() => { setApproveOpen(false); onApprove(candidate.id); }}
        onCancel={() => setApproveOpen(false)}
      />

      <tr
        className={`group transition-all duration-200 hover:bg-yellow-50/40 ${
          isGold ? "bg-yellow-50/60" : "bg-white even:bg-gray-50/50"
        }`}
      >
        {/* Rank */}
        <td className="px-4 py-3 text-center w-12">
          <span
            className={`inline-flex items-center justify-center w-7 h-7 rounded-full text-xs font-bold ${
              isGold
                ? "bg-yellow-400 text-yellow-900 shadow-[0_0_8px_rgba(234,179,8,0.6)]"
                : "bg-gray-100 text-gray-500"
            }`}
          >
            {rank}
          </span>
        </td>

        {/* Nom */}
        <td className={`px-4 py-3 ${isGold ? GOLD_BORDER.replace("border-2", "") : ""}`}>
          <div className="flex items-center gap-2">
            {/* Avatar initiales */}
            <div
              className={`w-8 h-8 rounded-full flex items-center justify-center text-xs font-bold flex-shrink-0 ${
                isGold
                  ? "bg-yellow-400 text-yellow-900"
                  : "bg-indigo-100 text-indigo-700"
              }`}
            >
              {(candidate.nomPrenom || candidate.name || "?")
                .split(" ")
                .map((n) => n[0])
                .join("")
                .slice(0, 2)
                .toUpperCase()}
            </div>
            <div>
              <p className="font-semibold text-gray-800 text-sm leading-tight">
                {candidate.nomPrenom || candidate.name || "—"}
              </p>
              {isGold && (
                <span className={GOLD_BADGE}>
                  ★ Top 5
                </span>
              )}
            </div>
          </div>
        </td>

        {/* Email */}
        <td className="px-4 py-3 text-gray-500 text-sm">
          {candidate.email || "—"}
        </td>

        {/* Score */}
        <td className="px-4 py-3 text-center">
          {candidate.score != null ? (
            <div className="flex items-center justify-center gap-1">
              <div className="w-20 h-2 bg-gray-200 rounded-full overflow-hidden">
                <div
                  className={`h-2 rounded-full ${
                    isGold ? "bg-yellow-400" : "bg-indigo-500"
                  }`}
                  style={{ width: `${Math.min(100, candidate.score)}%` }}
                />
              </div>
              <span className={`text-xs font-bold ${isGold ? "text-yellow-600" : "text-gray-700"}`}>
                {candidate.score}%
              </span>
            </div>
          ) : (
            <span className="text-gray-400 text-xs">—</span>
          )}
        </td>

        {/* Statut */}
        <td className="px-4 py-3 text-center">
          <span
            className={`inline-block text-[11px] font-semibold px-2.5 py-0.5 rounded-full ${
              statusColors[candidate.statut] || "bg-gray-100 text-gray-600"
            }`}
          >
            {candidate.statut || "En attente"}
          </span>
        </td>

        {/* Date */}
        <td className="px-4 py-3 text-gray-400 text-xs text-center whitespace-nowrap">
          {candidate.datePostulation
            ? new Date(candidate.datePostulation).toLocaleDateString("fr-FR")
            : "—"}
        </td>

        {/* Actions */}
        <td className="px-4 py-3">
          <div className="flex items-center gap-2 justify-end">
            {/* Approuver */}
            <button
              onClick={() => setApproveOpen(true)}
              title="Approuver le candidat (envoi email)"
              className="inline-flex items-center gap-1 px-3 py-1.5 rounded-lg bg-green-50 text-green-700 border border-green-200 hover:bg-green-600 hover:text-white hover:border-green-600 text-xs font-semibold transition-all duration-150 shadow-sm"
            >
              <svg className="w-3.5 h-3.5" viewBox="0 0 20 20" fill="currentColor">
                <path fillRule="evenodd" d="M16.707 5.293a1 1 0 010 1.414L8.414 15l-4.121-4.121a1 1 0 011.414-1.414L8.414 12.172l6.879-6.879a1 1 0 011.414 0z" clipRule="evenodd"/>
              </svg>
              Approuver
            </button>

            {/* Supprimer */}
            <button
              onClick={() => setDeleteOpen(true)}
              title="Supprimer ce candidat"
              className="inline-flex items-center gap-1 px-3 py-1.5 rounded-lg bg-red-50 text-red-600 border border-red-200 hover:bg-red-600 hover:text-white hover:border-red-600 text-xs font-semibold transition-all duration-150 shadow-sm"
            >
              <svg className="w-3.5 h-3.5" viewBox="0 0 20 20" fill="currentColor">
                <path fillRule="evenodd" d="M9 2a1 1 0 00-.894.553L7.382 4H4a1 1 0 000 2v10a2 2 0 002 2h8a2 2 0 002-2V6a1 1 0 100-2h-3.382l-.724-1.447A1 1 0 0011 2H9zM7 8a1 1 0 012 0v6a1 1 0 11-2 0V8zm5-1a1 1 0 00-1 1v6a1 1 0 102 0V8a1 1 0 00-1-1z" clipRule="evenodd"/>
              </svg>
              Supprimer
            </button>
          </div>
        </td>
      </tr>
    </>
  );
}

// ── main component ─────────────────────────────────────────────────────────────

export default function JobOfferDetail() {
  const { id } = useParams();
  const navigate = useNavigate();

  const [offer, setOffer] = useState(null);
  const [allCandidates, setAllCandidates] = useState([]);
  const [visibleCount, setVisibleCount] = useState(PAGE_SIZE);
  const [loading, setLoading] = useState(true);
  const [loadingMore, setLoadingMore] = useState(false);
  const [error, setError] = useState(null);

  // ── fetch data ────────────────────────────────────────────────────────────────
  const fetchData = useCallback(async () => {
    try {
      setLoading(true);
      const [offerRes, candidatesRes] = await Promise.all([
        api.get(`/job-offers/${id}`),
        api.get(`/job-offers/${id}/candidates`),
      ]);
      setOffer(offerRes.data);

      // Trier : top 5 (score desc) en premier, puis le reste
      const raw = candidatesRes.data || [];
      const sorted = [...raw].sort((a, b) => (b.score ?? 0) - (a.score ?? 0));
      setAllCandidates(sorted);
    } catch (err) {
      setError("Impossible de charger les données.");
      console.error(err);
    } finally {
      setLoading(false);
    }
  }, [id]);

  useEffect(() => { fetchData(); }, [fetchData]);

  // ── actions ───────────────────────────────────────────────────────────────────
  const handleDelete = async (candidateId) => {
    try {
      await api.delete(`/candidates/${candidateId}`);
      setAllCandidates((prev) => prev.filter((c) => c.id !== candidateId));
    } catch (err) {
      alert("Erreur lors de la suppression.");
      console.error(err);
    }
  };

  // Bouton approuver : visuel seulement pour l'instant (workflow n8n à brancher plus tard)
  const handleApprove = (candidateId) => {
    console.log(`[TODO] Déclencher workflow n8n pour candidat #${candidateId}`);
    // TODO: POST /api/candidates/:id/approve  → n8n workflow 3
  };

  const handleLoadMore = async () => {
    setLoadingMore(true);
    await new Promise((r) => setTimeout(r, 300)); // légère pause UX
    setVisibleCount((prev) => prev + PAGE_SIZE);
    setLoadingMore(false);
  };

  // ── derived ───────────────────────────────────────────────────────────────────
  const visibleCandidates = allCandidates.slice(0, visibleCount);
  const hasMore = visibleCount < allCandidates.length;

  // ── render ────────────────────────────────────────────────────────────────────
  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-[60vh]">
        <div className="flex flex-col items-center gap-3">
          <svg className="w-10 h-10 text-indigo-500 animate-spin" viewBox="0 0 24 24" fill="none">
            <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"/>
            <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8v8H4z"/>
          </svg>
          <p className="text-gray-500 text-sm">Chargement de l'offre…</p>
        </div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[60vh] gap-4">
        <p className="text-red-500 font-medium">{error}</p>
        <button onClick={() => navigate(-1)} className="text-sm text-indigo-600 underline">
          ← Retour
        </button>
      </div>
    );
  }

  return (
    <div className="max-w-7xl mx-auto px-4 py-8">

      {/* ── Header offre ──────────────────────────────────────────────────────── */}
      <div className="mb-8">
        <button
          onClick={() => navigate(-1)}
          className="flex items-center gap-1 text-sm text-gray-500 hover:text-indigo-600 transition mb-4"
        >
          <svg className="w-4 h-4" viewBox="0 0 20 20" fill="currentColor">
            <path fillRule="evenodd" d="M9.707 16.707a1 1 0 01-1.414 0l-6-6a1 1 0 010-1.414l6-6a1 1 0 011.414 1.414L5.414 9H17a1 1 0 110 2H5.414l4.293 4.293a1 1 0 010 1.414z" clipRule="evenodd"/>
          </svg>
          Retour aux offres
        </button>

        <div className="flex flex-col md:flex-row md:items-center md:justify-between gap-4 bg-white rounded-2xl border border-gray-100 shadow-sm p-6">
          <div>
            <h1 className="text-2xl font-bold text-gray-900">
              {offer?.titre || offer?.title || "Offre d'emploi"}
            </h1>
            <p className="text-gray-500 text-sm mt-1">
              {offer?.departement && <span className="mr-3">🏢 {offer.departement}</span>}
              {offer?.localisation && <span className="mr-3">📍 {offer.localisation}</span>}
              {offer?.typeContrat && <span>📄 {offer.typeContrat}</span>}
            </p>
          </div>
          <div className="flex items-center gap-3 flex-shrink-0">
            <div className="text-right">
              <p className="text-3xl font-black text-indigo-600">{allCandidates.length}</p>
              <p className="text-xs text-gray-400 font-medium uppercase tracking-wide">Candidats</p>
            </div>
          </div>
        </div>
      </div>

      {/* ── Légende Top 5 ─────────────────────────────────────────────────────── */}
      {allCandidates.length > 0 && (
        <div className="mb-4 flex items-center gap-2">
          <span className="inline-flex items-center gap-1.5 bg-yellow-50 border border-yellow-300 text-yellow-800 text-xs font-semibold px-3 py-1.5 rounded-full">
            <span className="text-yellow-500 text-sm">★</span>
            Les 5 premiers candidats (meilleur score) sont mis en avant avec un cadre doré
          </span>
        </div>
      )}

      {/* ── Tableau candidats ─────────────────────────────────────────────────── */}
      {allCandidates.length === 0 ? (
        <div className="bg-white rounded-2xl border border-dashed border-gray-200 p-16 text-center">
          <p className="text-4xl mb-3">📭</p>
          <p className="text-gray-500 font-medium">Aucun candidat pour cette offre.</p>
        </div>
      ) : (
        <div className="bg-white rounded-2xl border border-gray-100 shadow-sm overflow-hidden">
          <div className="overflow-x-auto">
            <table className="w-full text-sm">
              <thead>
                <tr className="bg-gray-50 border-b border-gray-100">
                  <th className="px-4 py-3 text-center text-xs font-semibold text-gray-400 uppercase tracking-wider w-12">#</th>
                  <th className="px-4 py-3 text-left text-xs font-semibold text-gray-400 uppercase tracking-wider">Candidat</th>
                  <th className="px-4 py-3 text-left text-xs font-semibold text-gray-400 uppercase tracking-wider">Email</th>
                  <th className="px-4 py-3 text-center text-xs font-semibold text-gray-400 uppercase tracking-wider">Score IA</th>
                  <th className="px-4 py-3 text-center text-xs font-semibold text-gray-400 uppercase tracking-wider">Statut</th>
                  <th className="px-4 py-3 text-center text-xs font-semibold text-gray-400 uppercase tracking-wider">Date</th>
                  <th className="px-4 py-3 text-right text-xs font-semibold text-gray-400 uppercase tracking-wider">Actions</th>
                </tr>
              </thead>

              <tbody className="divide-y divide-gray-100">
                {visibleCandidates.map((candidate, index) => {
                  const rank = index + 1;
                  const isGold = rank <= 5;
                  return (
                    <CandidateRow
                      key={candidate.id}
                      candidate={candidate}
                      rank={rank}
                      isGold={isGold}
                      onDelete={handleDelete}
                      onApprove={handleApprove}
                    />
                  );
                })}
              </tbody>
            </table>
          </div>

          {/* ── Footer : Load more ──────────────────────────────────────────────── */}
          <div className="px-6 py-4 border-t border-gray-100 flex items-center justify-between bg-gray-50/50">
            <p className="text-xs text-gray-400">
              Affichage de{" "}
              <span className="font-semibold text-gray-600">{visibleCandidates.length}</span>
              {" "}sur{" "}
              <span className="font-semibold text-gray-600">{allCandidates.length}</span>
              {" "}candidats
            </p>

            {hasMore ? (
              <button
                onClick={handleLoadMore}
                disabled={loadingMore}
                className="inline-flex items-center gap-2 px-5 py-2 rounded-xl bg-indigo-600 text-white text-sm font-semibold hover:bg-indigo-700 disabled:opacity-50 disabled:cursor-not-allowed transition shadow-sm"
              >
                {loadingMore ? (
                  <>
                    <svg className="w-4 h-4 animate-spin" viewBox="0 0 24 24" fill="none">
                      <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"/>
                      <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8v8H4z"/>
                    </svg>
                    Chargement…
                  </>
                ) : (
                  <>
                    Charger {Math.min(PAGE_SIZE, allCandidates.length - visibleCount)} de plus
                    <svg className="w-4 h-4" viewBox="0 0 20 20" fill="currentColor">
                      <path fillRule="evenodd" d="M5.293 7.293a1 1 0 011.414 0L10 10.586l3.293-3.293a1 1 0 111.414 1.414l-4 4a1 1 0 01-1.414 0l-4-4a1 1 0 010-1.414z" clipRule="evenodd"/>
                    </svg>
                  </>
                )}
              </button>
            ) : (
              <p className="text-xs text-gray-400 italic">Tous les candidats sont affichés</p>
            )}
          </div>
        </div>
      )}
    </div>
  );
}
